#include <iostream>
#include <string>
#include <set>
using namespace std;



int a = 0;
int r = 0;
string li[2] = { "" ,"" };

int main() {
    cin >> a;
    if (a == 3) {
        cout << "!\n!!\n!!!";
    }
    else {
        string dum = "0123456789QWERTYUIOPASDFGHJKLZXCVBNMqwertyuiopasdfghjklzxcvbnm";
        for (int k = 0; k < 2; k++) {
            int poi = 0;
            for (int i = 0; i < 62 - 26; i++) {
                for (int j = 0; j < 62; j++) {
                    while (li[k][poi] != '/') {
                        if (k == 0)cout << dum[i] << dum[j] << li[k][poi] << "\n";
                        if (k == 1)cout << dum[i] << dum[j] << li[k][poi] << li[k][poi + 1] << "\n";
                        r += 1;
                        if (r == a) break;
                        poi += 1 + k;
                    }
                    poi += 1;
                    if (r == a) break;
                }
                if (r == a) break;
            }
            if (r == a) break;
        }
    }
}
